final:
module gray_counter (
    input clk,
    input rst,
    output reg [3:0] gray
);
    reg [3:0] unused_binary;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            unused_binary <= 4'b0000;
            gray <= 4'b0000;
        end else begin
            unused_binary <= unused_binary + 1;
            gray <= (unused_binary >> 1) ^ unused_binary;
        end
    end
endmodule
